SELECT FROM_USR_ID FROM AP_DELEGATE
 WHERE DEL_YN='N' AND USE_YN='Y' AND TO_USR_ID=#{toUsrId}
   AND TO_DATE(#{ymd},'YYYY-MM-DD') BETWEEN VALID_SD AND VALID_ED

SELECT COUNT(*) FROM AP_DELEGATE
 WHERE DEL_YN='N' AND USE_YN='Y' AND FROM_USR_ID=#{fromUsrId} AND TO_USR_ID=#{toUsrId}
   AND TO_DATE(#{ymd},'YYYY-MM-DD') BETWEEN VALID_SD AND VALID_ED

mapper.update:
UPDATE AP_DELEGATE SET FROM_USR_ID=#{fromUsrId}, FROM_USR_NM=#{fromUsrNm}, TO_USR_ID=#{toUsrId}, TO_USR_NM=#{toUsrNm},
       VALID_SD=TO_DATE(#{validSd},'YYYY-MM-DD'), VALID_ED=TO_DATE(#{validEd},'YYYY-MM-DD'),
       REMARK=#{remark}, USE_YN=#{useYn}, MOD_ID=#{regId}, MOD_DT=SYSTIMESTAMP WHERE ID=#{id}
